import numpy as np

def predict(frame, action):
    f = frame.copy()
    H, W = f.shape
    block_colors = (9, 10)
    mask = np.isin(f, block_colors)
    visited = np.zeros_like(mask, dtype=bool)
    comps = []
    for i in range(H):
        for j in range(W):
            if mask[i, j] and not visited[i, j]:
                stack = [(i, j)]; visited[i, j] = True; cells = []
                while stack:
                    r, c = stack.pop(); cells.append((r, c))
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < H and 0 <= nc < W and mask[nr, nc] and not visited[nr, nc]:
                            visited[nr, nc] = True; stack.append((nr, nc))
                comps.append(cells)
    if not comps:
        return f

    # active block = lowest (max bottom row), tie-break rightmost
    active = max(comps, key=lambda cs: (max(r for r, _ in cs), max(c for _, c in cs)))
    rs = [r for r, _ in active]; cs = [c for _, c in active]
    r0, r1 = min(rs), max(rs); c0, c1 = min(cs), max(cs)
    h = r1 - r0 + 1; w = c1 - c0 + 1

    if action == 1:                      # fixed: top=9, bottom=10
        midr = r0 + h // 2
        for r, c in active:
            f[r, c] = 9 if r < midr else 10
    elif action == 2:                    # fixed: top=10, bottom=9
        midr = r0 + h // 2
        for r, c in active:
            f[r, c] = 10 if r < midr else 9
    elif action == 3:                    # roll left only into an existing trail
        if c0 - w >= 0 and all(f[r, c] == 2
                               for r in range(r0, r1 + 1)
                               for c in range(c0 - w, c0)):
            for r, c in active:
                f[r, c] = 2
            midc = (c0 - w) + w // 2
            for r in range(r0, r1 + 1):
                for c in range(c0 - w, c0):
                    f[r, c] = 9 if c < midc else 10
    elif action == 4:                    # roll right only into an existing trail
        if c1 + w < W and all(f[r, c] == 2
                              for r in range(r0, r1 + 1)
                              for c in range(c1 + 1, c1 + 1 + w)):
            for r, c in active:
                f[r, c] = 2
            base = c1 + 1; midc = base + w // 2
            for r in range(r0, r1 + 1):
                for c in range(base, base + w):
                    f[r, c] = 10 if c < midc else 9
    # action 6 / others: no change
    return f
